validator cip068_nft_ft_mint_burn {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pairs = dict.to_pairs(tokens)
    let label_ref = #"000643b0"
    let label_nft = #"000de140"
    let label_ft = #"0014df10"
    list.all(
      pairs,
      fn(pair) {
        let Pair(name, qty) = pair
        let prefix = bytearray.take(name, 4)
        let content = bytearray.drop(name, 4)
        if qty > 0 {
          if prefix == label_nft {
            let ref_name = bytearray.concat(label_ref, content)
            qty == 1 && dict.get(tokens, ref_name) == Some(1)
          } else if prefix == label_ft {
            let ref_name = bytearray.concat(label_ref, content)
            qty > 0 && dict.get(tokens, ref_name) == Some(1)
          } else if prefix == label_ref {
            // reference NFT: qty must be 1, and either an NFT or FT user token must exist
            let nft_user = bytearray.concat(label_nft, content)
            let ft_user = bytearray.concat(label_ft, content)
            let has_nft = dict.has_key(tokens, nft_user)
            let has_ft = dict.has_key(tokens, ft_user)
            qty == 1 && (has_nft || has_ft)
          } else {
            False
          }
        } else {
          // burning
          if prefix == label_nft || prefix == label_ref {
            qty == -1
          } else if prefix == label_ft {
            qty < 0
          } else {
            False
          }
        }
      },
    )
  }
}

use aiken/collection/dict
use aiken/collection/list
use aiken/primitive/bytearray
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Transaction}

fn validate_mint(
  name: AssetName,
  qty: Int,
  tokens: dict.Dict<AssetName, Int>,
) -> Bool {
  let prefix = bytearray.take(name, 4)
  let content = bytearray.drop(name, 4)
  when prefix is {
    #"000de140" -> {
      let ref_name = bytearray.concat(#"000643b0", content)
      qty == 1 && dict.get(tokens, ref_name) == Some(1)
    }
    #"000643b0" -> {
      let user_name = bytearray.concat(#"000de140", content)
      qty == 1 && dict.get(tokens, user_name) == Some(1)
    }
    _ -> False
  }
}

fn validate_burn(name: AssetName, qty: Int) -> Bool {
  let prefix = bytearray.take(name, 4)
  when prefix is {
    #"000de140" -> qty == -1
    #"000643b0" -> qty == -1
    _ -> False
  }
}

validator cip068_split_helpers {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pairs = dict.to_pairs(tokens)
    list.all(
      pairs,
      fn(pair) {
        let Pair(name, qty) = pair
        if qty > 0 {
          validate_mint(name, qty, tokens)
        } else {
          validate_burn(name, qty)
        }
      },
    )
  }
}

