use cardano/transaction.{Transaction}

validator cip068_length_check {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pairs = dict.to_pairs(tokens)
    list.all(
      pairs,
      fn(pair) {
        let Pair(name, qty) = pair
        expect bytearray.length(name) >= 4
        let prefix = bytearray.take(name, 4)
        let content = bytearray.drop(name, 4)
        if qty > 0 {
          // minting path
          when prefix is {
            #"000de140" -> {
              // user NFT must pair with reference NFT
              let ref_name = bytearray.concat(#"000643b0", content)
              and {
                qty == 1,
                dict.get(tokens, ref_name) == Some(1),
                bytearray.length(content) > 0,
              }
            }
            #"000643b0" -> {
              // reference NFT must pair with user NFT
              let user_name = bytearray.concat(#"000de140", content)
              and {
                qty == 1,
                dict.get(tokens, user_name) == Some(1),
                bytearray.length(content) > 0,
              }
            }
            _ -> False
          }
        } else {
          // burning path: only known prefixes, qty must be -1
          and {
            or {
              prefix == #"000de140",
              prefix == #"000643b0",
            },
            qty == -1,
          }
        }
      },
    )
  }
}

use aiken/collection/dict
use aiken/collection/list
use aiken/primitive/bytearray
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Transaction}

validator cip068_acunar_quemar {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pares = dict.to_pairs(tokens)
    let prefijo_ref = #"000643b0"
    let prefijo_usuario = #"000de140"
    list.all(
      pares,
      fn(par) {
        let Pair(nombre, cantidad) = par
        let prefijo = bytearray.take(nombre, 4)
        let contenido = bytearray.drop(nombre, 4)
        if cantidad > 0 {
          // Acuñación: verificar emparejamiento
          if prefijo == prefijo_usuario {
            let nombre_ref = bytearray.concat(prefijo_ref, contenido)
            cantidad == 1 && dict.get(tokens, nombre_ref) == Some(1)
          } else if prefijo == prefijo_ref {
            let nombre_usuario = bytearray.concat(prefijo_usuario, contenido)
            cantidad == 1 && dict.get(tokens, nombre_usuario) == Some(1)
          } else {
            False
          }
        } else {
          // Quema: verificar que la cantidad sea -1 para NFTs
          if prefijo == prefijo_usuario || prefijo == prefijo_ref {
            cantidad == -1
          } else {
            False
          }
        }
      },
    )
  }
}

use aiken/collection/dict
use aiken/collection/list
use aiken/primitive/bytearray
use cardano/assets.{AssetName, PolicyId}
use cardano/transaction.{Transaction}

fn es_acunar_valido(
  nombre: AssetName,
  cantidad: Int,
  tokens: dict.Dict<AssetName, Int>,
) -> Bool {
  let prefijo = bytearray.take(nombre, 4)
  let contenido = bytearray.drop(nombre, 4)
  let etiqueta_ref = #"000643b0"
  let etiqueta_nft = #"000de140"
  let etiqueta_ft = #"0014df10"
  when prefijo is {
    #"000de140" -> {
      let ref = bytearray.concat(etiqueta_ref, contenido)
      cantidad == 1 && dict.get(tokens, ref) == Some(1)
    }
    #"0014df10" -> {
      let ref = bytearray.concat(etiqueta_ref, contenido)
      cantidad > 0 && dict.get(tokens, ref) == Some(1)
    }
    #"000643b0" -> {
      let tiene_nft = dict.has_key(tokens, bytearray.concat(etiqueta_nft, contenido))
      let tiene_ft = dict.has_key(tokens, bytearray.concat(etiqueta_ft, contenido))
      cantidad == 1 && (tiene_nft || tiene_ft)
    }
    _ -> False
  }
}

fn es_quema_valida(nombre: AssetName, cantidad: Int) -> Bool {
  let prefijo = bytearray.take(nombre, 4)
  when prefijo is {
    #"000de140" -> cantidad == -1
    #"000643b0" -> cantidad == -1
    #"0014df10" -> cantidad < 0
    _ -> False
  }
}

validator cip068_nft_ft_es {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pares = dict.to_pairs(tokens)
    list.all(
      pares,
      fn(par) {
        let Pair(nombre, cantidad) = par
        if cantidad > 0 {
          es_acunar_valido(nombre, cantidad, tokens)
        } else {
          es_quema_valida(nombre, cantidad)
        }
      },
    )
  }
}

