        expect longitud >= 5
        let prefijo = bytearray.take(nombre, 4)
        let contenido = bytearray.drop(nombre, 4)
        if cantidad > 0 {
          // Ruta de acuñación
          when prefijo is {
            #"000de140" -> {
              let nombre_ref = bytearray.concat(#"000643b0", contenido)
              and {
                cantidad == 1,
                dict.get(tokens, nombre_ref) == Some(1),
              }
            }
            #"000643b0" -> {
              let nombre_usr = bytearray.concat(#"000de140", contenido)
              and {
                cantidad == 1,
                dict.get(tokens, nombre_usr) == Some(1),
              }
            }
            _ -> False
          }
        } else {
          // Ruta de quema
          and {
            or {
              prefijo == #"000de140",
              prefijo == #"000643b0",
            },
            cantidad == -1,
          }
        }
      },
    )
  }
}

use aiken/collection/dict
use aiken/collection/list
use aiken/primitive/bytearray
use cardano/assets.{AssetName, PolicyId}
