fn validar_acunar(
  nombre: AssetName,
  cantidad: Int,
  tokens: dict.Dict<AssetName, Int>,
) -> Bool {
  let prefijo = bytearray.take(nombre, 4)
  let contenido = bytearray.drop(nombre, 4)
  when prefijo is {
    #"000de140" -> {
      let par_ref = bytearray.concat(#"000643b0", contenido)
      and {
        cantidad == 1,
        dict.get(tokens, par_ref) == Some(1),
      }
    }
    #"000643b0" -> {
      let par_usr = bytearray.concat(#"000de140", contenido)
      and {
        cantidad == 1,
        dict.get(tokens, par_usr) == Some(1),
      }
    }
    _ -> False
  }
}

fn validar_quemar(
  nombre: AssetName,
  cantidad: Int,
  tokens: dict.Dict<AssetName, Int>,
) -> Bool {
  let prefijo = bytearray.take(nombre, 4)
  let contenido = bytearray.drop(nombre, 4)
  when prefijo is {
    #"000de140" -> {
      // Al quemar el token de usuario, el ref también debe quemarse
      let par_ref = bytearray.concat(#"000643b0", contenido)
      and {
        cantidad == -1,
        dict.get(tokens, par_ref) == Some(-1),
      }
    }
    #"000643b0" -> {
      // Al quemar el ref, el usuario también debe quemarse
      let par_usr = bytearray.concat(#"000de140", contenido)
      and {
        cantidad == -1,
        dict.get(tokens, par_usr) == Some(-1),
      }
    }
    _ -> False
  }
}

validator cip068_quema_en_pares {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pares = dict.to_pairs(tokens)
    list.all(
      pares,
      fn(par) {
        let Pair(nombre, cantidad) = par
        if cantidad > 0 {
          validar_acunar(nombre, cantidad, tokens)
        } else {
          validar_quemar(nombre, cantidad, tokens)
        }
      },
    )
  }
}

use aiken/collection/dict
use aiken/collection/list
