validator cip068_ft_basic {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pairs = dict.to_pairs(tokens)
    let ref_prefix = #"000643b0"
    let ft_prefix = #"0014df10"
    list.all(
      pairs,
      fn(pair) {
        let Pair(name, qty) = pair
        if bytearray.take(name, 4) == ft_prefix {
          // FT must have positive quantity
          expect qty > 0
          let content = bytearray.drop(name, 4)
          let expected_ref_name = bytearray.concat(ref_prefix, content)
          // Must find matching reference NFT with qty == 1
          when dict.get(tokens, expected_ref_name) is {
            Some(ref_qty) -> ref_qty == 1
            None -> False
          }
        } else if bytearray.take(name, 4) == ref_prefix {
          // Reference NFT must be exactly 1
          qty == 1
        } else {
          // Unknown prefix, reject
          False
        }
      },
    )
  }
}

