use aiken/collection/dict
use aiken/collection/list
use aiken/primitive/bytearray
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction}

validator cip068_ft_name_length {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pairs = dict.to_pairs(tokens)
    let ref_prefix = #"000643b0"
    let ft_prefix = #"0014df10"
    // Separate FTs and refs
    let ft_pairs =
      list.filter(
        pairs,
        fn(p) {
          let Pair(n, _q) = p
          bytearray.take(n, 4) == ft_prefix
        },
      )
    let ref_pairs =
      list.filter(
        pairs,
        fn(p) {
          let Pair(n, _q) = p
          bytearray.take(n, 4) == ref_prefix
        },
      )
    // Total minted tokens must be only FTs and refs
    let total_count = list.length(ft_pairs) + list.length(ref_pairs)
    expect total_count == list.length(pairs)
    // Validate each FT
    list.all(
      ft_pairs,
      fn(pair) {
        let Pair(name, qty) = pair
        // Must have content after prefix
        let name_len = bytearray.length(name)
        expect name_len > 4
        expect qty > 0
        let content = bytearray.drop(name, 4)
        let expected_ref = bytearray.concat(ref_prefix, content)
        when dict.get(tokens, expected_ref) is {
          Some(rq) -> rq == 1
          None -> False
        }
      },
    ) && list.all(
      ref_pairs,
      fn(pair) {
        let Pair(name, qty) = pair
        expect bytearray.length(name) > 4
        qty == 1
      },
    )
  }
}

