pub type FTRedeemer {
  max_supply: Int,
}

validator cip068_ft_max_supply {
  mint(redeemer: FTRedeemer, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pairs = dict.to_pairs(tokens)
    let ref_prefix = #"000643b0"
    let ft_prefix = #"0014df10"
    // Sum all FT quantities
    let total_ft_minted =
      list.foldl(
        pairs,
        0,
        fn(pair, acc) {
          let Pair(name, qty) = pair
          if bytearray.take(name, 4) == ft_prefix {
            acc + qty
          } else {
            acc
          }
        },
      )
    // Enforce max supply
    expect total_ft_minted > 0
    expect total_ft_minted <= redeemer.max_supply
    // Validate pairing
    list.all(
      pairs,
      fn(pair) {
        let Pair(name, qty) = pair
        let prefix = bytearray.take(name, 4)
        if prefix == ft_prefix {
          expect qty > 0
          let content = bytearray.drop(name, 4)
          let ref_name = bytearray.concat(ref_prefix, content)
          when dict.get(tokens, ref_name) is {
            Some(rq) -> rq == 1
            None -> False
          }
        } else if prefix == ref_prefix {
          qty == 1
        } else {
          False
        }
      },
    )
  }
}

