/// Validador CIP-0068 FT que permite acuñar y quemar
validator cip068_ft_con_quema {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pares = dict.to_pairs(tokens)
    let prefijo_ref = #"000643b0"
    let prefijo_ft = #"0014df10"
    list.all(
      pares,
      fn(par) {
        let Pair(nombre, cantidad) = par
        let prefijo = bytearray.take(nombre, 4)
        if cantidad < 0 {
          // La quema se permite para FTs y NFTs de referencia
          prefijo == prefijo_ft || prefijo == prefijo_ref
        } else if prefijo == prefijo_ft {
          // Acuñacion de FT: cantidad positiva y emparejamiento requerido
          expect cantidad > 0
          let contenido = bytearray.drop(nombre, 4)
          let nombre_ref = bytearray.concat(prefijo_ref, contenido)
          when dict.get(tokens, nombre_ref) is {
            Some(cant_ref) -> cant_ref == 1
            None -> False
          }
        } else if prefijo == prefijo_ref {
          cantidad == 1
        } else {
          False
        }
      },
    )
  }
}

