pub type RedeemerFT {
  suministro_maximo: Int,
}

/// Validador CIP-0068 FT con control de suministro maximo
validator cip068_ft_suministro_max {
  mint(
    redeemer: RedeemerFT,
    policy_id: PolicyId,
    self: Transaction,
  ) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pares = dict.to_pairs(tokens)
    let prefijo_ref = #"000643b0"
    let prefijo_ft = #"0014df10"
    // Sumar todas las cantidades de FT acuñados
    let total_ft =
      list.foldl(
        pares,
        0,
        fn(par, acumulador) {
          let Pair(nombre, cantidad) = par
          if bytearray.take(nombre, 4) == prefijo_ft {
            acumulador + cantidad
          } else {
            acumulador
          }
        },
      )
    // Verificar que se acuñe al menos 1 y no mas del maximo
    expect total_ft > 0
    expect total_ft <= redeemer.suministro_maximo
    // Validar emparejamiento
    list.all(
      pares,
      fn(par) {
        let Pair(nombre, cantidad) = par
        let prefijo = bytearray.take(nombre, 4)
        if prefijo == prefijo_ft {
          expect cantidad > 0
          let contenido = bytearray.drop(nombre, 4)
          let nombre_ref = bytearray.concat(prefijo_ref, contenido)
          when dict.get(tokens, nombre_ref) is {
            Some(cr) -> cr == 1
            None -> False
          }
        } else if prefijo == prefijo_ref {
          cantidad == 1
        } else {
          False
        }
      },
    )
  }
}

use aiken/collection/dict
use aiken/collection/list
use aiken/primitive/bytearray
use cardano/assets.{PolicyId, AssetName}
use cardano/transaction.{Transaction}

/// Validador CIP-0068 FT completo con multiples verificaciones
validator cip068_ft_completo {
  mint(_redeemer: Data, policy_id: PolicyId, self: Transaction) -> Bool {
    let tokens = assets.tokens(self.mint, policy_id)
    let pares = dict.to_pairs(tokens)
    let prefijo_ref = #"000643b0"
    let prefijo_ft = #"0014df10"
    // Separar tokens por tipo
    let pares_ft =
      list.filter(
        pares,
        fn(p) {
          let Pair(n, _c) = p
          bytearray.take(n, 4) == prefijo_ft
        },
      )
    let pares_ref =
      list.filter(
        pares,
        fn(p) {
          let Pair(n, _c) = p
          bytearray.take(n, 4) == prefijo_ref
        },
      )
    // No deben existir tokens con prefijos desconocidos
    let total_conocidos = list.length(pares_ft) + list.length(pares_ref)
    expect total_conocidos == list.length(pares)
    // Debe haber exactamente un FT y un NFT de referencia
    expect list.length(pares_ft) == 1
    expect list.length(pares_ref) == 1
    // Validar cada FT
    let ft_valido =
      list.all(
        pares_ft,
        fn(par) {
          let Pair(nombre, cantidad) = par
          // Longitud minima: 4 bytes de prefijo + al menos 1 byte de contenido
          expect bytearray.length(nombre) > 4
          expect cantidad > 0
          let contenido = bytearray.drop(nombre, 4)
          let nombre_ref_esperado =
            bytearray.concat(prefijo_ref, contenido)
          when dict.get(tokens, nombre_ref_esperado) is {
            Some(cr) -> cr == 1
            None -> False
          }
        },
      )
    // Validar cada NFT de referencia
    let ref_valido =
      list.all(
        pares_ref,
        fn(par) {
          let Pair(nombre, cantidad) = par
          expect bytearray.length(nombre) > 4
          expect cantidad == 1
          let contenido = bytearray.drop(nombre, 4)
          let nombre_ft_esperado =
            bytearray.concat(prefijo_ft, contenido)
          // Verificar que el FT correspondiente existe
          when dict.get(tokens, nombre_ft_esperado) is {
            Some(cf) -> cf > 0
            None -> False
          }
        },
      )
    ft_valido && ref_valido
  }
}
